// Extract topic parts
const topicParts = msg.topic.split("/");

const client_id = topicParts[1];
const factory_id = topicParts[3];
const machine_id = topicParts[5];
const sensor_type = topicParts[6];

const payload = msg.payload;

// Init event
let event = {
    client_id,
    factory_id,
    machine_id,
    device_id: payload.device_id || "simulator",
    event_type: null,
    value: null,
    metadata: {}
};

// ----------------------
// PIECE DETECTION
// ----------------------
if (sensor_type === "distance") {
    const threshold = 7;

    const lastState = context.get("piece_present") || false;
    const currentState = payload.distance < threshold;

    if (currentState && !lastState) {
        event.event_type = "piece_detected";
        event.value = "1";
    }

    context.set("piece_present", currentState);
}

// ----------------------
// CLASSIFICATION
// ----------------------
if (sensor_type === "camera" && payload.class) {
    event.event_type = "classification";
    event.value = payload.class;
    event.metadata = {
        confidence: payload.confidence || 0.9
    };
}

// ----------------------
// MACHINE STATE (vibration)
// ----------------------
if (sensor_type === "vibration") {
    const threshold = 1.5;

    const lastState = context.get("machine_state") || "stopped";
    const currentState = payload.vibration > threshold ? "running" : "stopped";

    if (currentState !== lastState) {
        event.event_type = "machine_state";
        event.value = currentState;
    }

    context.set("machine_state", currentState);
}

// If no event → ignore
// if (!event.event_type) {
//     return null;
// }

msg.payload = event;
return msg;
